using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Extensions.AI;
using OpenAI;

// ── Tool state ──────────────────────────────────────────────────────────────

var notes = new List<string>();
var httpClient = new HttpClient();
httpClient.DefaultRequestHeaders.UserAgent.ParseAdd("ResearchAgent/1.0");

// ── Tool definitions ────────────────────────────────────────────────────────

[Description("Search the web for information on a query. Returns relevant snippets and titles.")]
async Task<string> SearchWeb([Description("The search query")] string query)
{
    Console.ForegroundColor = ConsoleColor.DarkYellow;
    Console.WriteLine($"  🔍 Searching: \"{query}\"");
    Console.ResetColor();

    try
    {
        var encoded = Uri.EscapeDataString(query);
        var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";
        var json = await httpClient.GetFromJsonAsync<JsonElement>(url);

        var results = new List<string>();

        var abstractText = json.GetProperty("Abstract").GetString();
        var abstractSource = json.GetProperty("AbstractSource").GetString();
        if (!string.IsNullOrWhiteSpace(abstractText))
            results.Add($"[{abstractSource}] {abstractText}");

        var heading = json.GetProperty("Heading").GetString();
        if (!string.IsNullOrWhiteSpace(heading) && results.Count == 0)
            results.Add($"Topic: {heading}");

        if (json.TryGetProperty("RelatedTopics", out var topics))
        {
            foreach (var topic in topics.EnumerateArray().Take(5))
            {
                if (topic.TryGetProperty("Text", out var text))
                {
                    var snippet = text.GetString();
                    if (!string.IsNullOrWhiteSpace(snippet))
                        results.Add($"- {snippet}");
                }
            }
        }

        return results.Count == 0
            ? $"No detailed results found for '{query}'. Try rephrasing or breaking into sub-queries."
            : string.Join("\n\n", results);
    }
    catch (Exception ex)
    {
        return $"Search error: {ex.Message}. Try a different query.";
    }
}

[Description("Save a research note to record important findings, facts, or insights.")]
string TakeNote(
    [Description("A short label for the note")] string title,
    [Description("The detailed content of the note")] string content)
{
    notes.Add($"## {title}\n{content}");
    Console.ForegroundColor = ConsoleColor.DarkCyan;
    Console.WriteLine($"  📝 Note saved: \"{title}\"");
    Console.ResetColor();
    return $"Note '{title}' saved. Total notes: {notes.Count}.";
}

[Description("Retrieve all research notes collected so far.")]
string GetNotes()
{
    if (notes.Count == 0)
        return "No notes saved yet.";
    return string.Join("\n\n---\n\n", notes);
}

// ── Agent setup ─────────────────────────────────────────────────────────────

var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_CHAT_MODEL") ?? "gpt-4o-mini";

IChatClient innerClient = new OpenAIClient(apiKey)
    .GetChatClient(model)
    .AsIChatClient();

using var chatClient = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation()
    .Build();

var tools = new List<AITool>
{
    AIFunctionFactory.Create(SearchWeb),
    AIFunctionFactory.Create(TakeNote),
    AIFunctionFactory.Create(GetNotes),
};

const string systemPrompt = """
    You are a research agent. Thoroughly research the topic the user provides.

    Workflow:
    1. Break the topic into 3-5 key sub-questions.
    2. Use SearchWeb to find information for each sub-question.
    3. Use TakeNote to record every important finding as you go.
    4. After gathering enough information, use GetNotes to review your notes.
    5. Synthesize everything into a comprehensive, well-structured summary.

    Be thorough: search from multiple angles. Always cite sources when available.
    """;

// ── Interactive loop ────────────────────────────────────────────────────────

Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔬 AI Research Agent           ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research.          ║");
Console.WriteLine("║  Type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Green;
    Console.Write("Research topic ▶ ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notes.Clear();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, systemPrompt),
        new(ChatRole.User,
            $"Research the following topic and provide a comprehensive summary:\n\n{topic}"),
    };

    var options = new ChatOptions { Tools = tools };

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching… (the agent will search the web and take notes)");
    Console.ResetColor();
    Console.WriteLine();

    try
    {
        var response = await chatClient.GetResponseAsync(messages, options);

        Console.ForegroundColor = ConsoleColor.White;
        Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
        Console.WriteLine("  📋 Research Summary");
        Console.WriteLine("━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━");
        Console.ResetColor();
        Console.WriteLine(response.Text);
        Console.WriteLine();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
        Console.WriteLine();
    }
}

Console.WriteLine("Goodbye! 👋");

